template <typename Element, size_t compute_iterations>
__global__ void bench_kernel(size_t len, const Element seed1, const Element seed2, 
                             Element* src, Element* result) {
  Element sum = 0;
  constexpr size_t static_chunk_size = 4096;

  size_t chunk_idx = blockIdx.x * static_chunk_size;
  if (chunk_idx < len) {
    sum = bench_block<Element, compute_iterations, static_chunk_size>(&src[chunk_idx]);
  }

  if (blockIdx.x == 0) {
    *result = sum;
  }
}

template <typename Element, size_t compute_iterations>
size_t bench(size_t len, const Element seed1, const Element seed2, Element* src) {
  Element* d_src;
  Element* d_result;
  Element result;

  cudaMalloc(&d_src, len * sizeof(Element));
  cudaMalloc(&d_result, sizeof(Element));
  cudaMemcpy(d_src, src, len * sizeof(Element), cudaMemcpyHostToDevice);

  constexpr size_t static_chunk_size = 4096;
  size_t num_blocks = (len + static_chunk_size - 1) / static_chunk_size;

  bench_kernel<Element, compute_iterations>(num_blocks, seed1, seed2, d_src, d_result);

  cudaMemcpy(&result, d_result, sizeof(Element), cudaMemcpyDeviceToHost);

  src[0] = result;

  cudaFree(d_src);
  cudaFree(d_result);

  return len;
}

auto runbench_warmup(void* c, size_t size) {
  const int num_elements = size / sizeof(double);
  auto timer_start = benchmark_clock::now();

  double* ptr = new (c) double[num_elements];

  bench<double, 16>(num_elements, 1., -1., ptr);

  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count();
}

template <typename Op>
auto measure_operation(Op op) {
  auto timer_start = benchmark_clock::now();
  op();
  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count() / 1000.;
}

template <typename Op>
auto benchmark_cuda(Op op) {
  constexpr int total_runs = 20;
  constexpr int total_half_thread_runs = 10;

  cudaDeviceProp deviceProp;
  cudaGetDeviceProperties(&deviceProp, 0);
  int max_threads = deviceProp.multiProcessorCount;

  auto duration = op();
  std::vector<decltype(duration)> measurements;

  for (int i = 1; i < total_runs; i++) {
    duration = op();
    measurements.push_back(duration);
  }

  if (max_threads > 1) {
    for (int i = 1; i < total_half_thread_runs; i++) {
      duration = op();
      measurements.push_back(duration);
    }
  }

  return *std::min_element(std::begin(measurements), std::end(measurements));
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_{memory_space}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements
            * compute_iterations_
            * 2
            * 1
        + total_elements - 1;
    return computations;
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <unsigned int compute_iterations>
void runbench(void* c, size_t size) {
  ComputeSpace cs{size, compute_iterations};

  float *c_as_float = new (c) float[cs.element_count<float>()];
  auto kernel_time_mad_sp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench<float, compute_iterations>(cs.element_count<float>(), 1.f, -1.f, c_as_float);
    });
  });

  double *c_as_double = new (c) double[cs.element_count<double>()];
  auto kernel_time_mad_dp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench<double, compute_iterations>(cs.element_count<double>(), 1., -1., c_as_double);
    });
  });

  int *c_as_int = new (c) int[cs.element_count<int>()];
  auto kernel_time_mad_int = benchmark_cuda([&] {
    return measure_operation([&] {
      bench<int, compute_iterations>(cs.element_count<int>(), 1, -1, c_as_int);
    });
  });

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) / static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_sp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp * 1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp * 1000. / (1000. * 1000. * 1000.)

            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) / static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_dp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp * 1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp * 1000. / (1000. * 1000. * 1000.)

            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) / static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_int << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int * 1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int * 1000. / (1000. * 1000. * 1000.)

            << std::endl;
}

